/*
 * energy_monitor.ino — AC Energy Monitor Dashboard (ESP32)
 *
 * Elements:
 *   1. ZMPT101B (GPIO 35) + SCT-013 (GPIO 34) + EmonLib  — V/I/P/PF
 *   2. ESP32 WiFi + MQTT (10-s publish) + HTTP /api/now   — remote access
 *   3. SSD1306 OLED (I²C 0x3C)                           — live display
 *   4. MicroSD (SPI CS=GPIO 5)                            — CSV log
 *   5. NTP                                               — timestamps
 */

#include <Wire.h>
#include <WiFi.h>
#include <PubSubClient.h>
#include <WebServer.h>
#include <Adafruit_SSD1306.h>
#include <EmonLib.h>
#include <SPI.h>
#include <SD.h>
#include <time.h>

// --- Config ---
const char* SSID      = "HomeNet";
const char* WIFI_PASS = "changeme";
const char* MQTT_HOST = "192.168.1.10";
#define SD_CS   5
#define V_PIN  35
#define I_PIN  34
#define VCAL   234.26f
#define ICAL   111.1f

// --- Objects ---
EnergyMonitor  emon;
Adafruit_SSD1306 oled(128, 64, &Wire, -1);
WiFiClient     wc;
PubSubClient   mqtt(wc);
WebServer      server(80);

// --- Data ---
float  v_rms = 0, i_rms = 0, real_p = 0, pf = 0;
double kwh_today = 0.0;
unsigned long last_measure = 0;

void update_oled() {
  oled.clearDisplay();
  oled.setTextSize(1); oled.setTextColor(SSD1306_WHITE);
  oled.setCursor(0,  0); oled.printf("V: %.1f V  I: %.2f A", v_rms, i_rms);
  oled.setCursor(0, 16); oled.printf("P: %.1f W", real_p);
  oled.setCursor(0, 28); oled.printf("PF: %.2f%s", pf, pf < 0.7f ? " ALERT" : "");
  oled.setCursor(0, 44); oled.printf("kWh today: %.3f", kwh_today);
  oled.display();
}

void log_sd(const char* ts) {
  if (!SD.begin(SD_CS)) return;
  File f = SD.open("/POWER.CSV", FILE_WRITE);
  if (f) {
    f.printf("%s,%.1f,%.3f,%.1f,%.2f,%.4f\n", ts, v_rms, i_rms, real_p, pf, kwh_today);
    f.close();
  }
  SD.end();
}

void mqtt_reconnect() {
  while (!mqtt.connected()) {
    if (mqtt.connect("EnergyMonitor")) break;
    delay(3000);
  }
}

void handle_api() {
  char buf[256];
  snprintf(buf, sizeof(buf),
    "{\"v_rms\":%.1f,\"i_rms\":%.3f,\"real_p\":%.1f,\"pf\":%.2f,\"kwh_today\":%.4f}",
    v_rms, i_rms, real_p, pf, kwh_today);
  server.send(200, "application/json", buf);
}

void setup() {
  Serial.begin(115200);
  Wire.begin();

  emon.voltage(V_PIN, VCAL, 1.7);  // pin, vcal, phase_shift
  emon.current(I_PIN, ICAL);

  oled.begin(SSD1306_SWITCHCAPVCC, 0x3C);
  oled.clearDisplay(); oled.display();

  WiFi.begin(SSID, WIFI_PASS);
  while (WiFi.status() != WL_CONNECTED) delay(500);
  configTime(0, 0, "pool.ntp.org");  // UTC

  mqtt.setServer(MQTT_HOST, 1883);
  mqtt_reconnect();

  server.on("/api/now", handle_api);
  server.begin();

  SPI.begin();
  Serial.println(F("Energy monitor ready. IP: " ));
  Serial.println(WiFi.localIP());
}

void loop() {
  if (!mqtt.connected()) mqtt_reconnect();
  mqtt.loop();
  server.handleClient();

  unsigned long now = millis();

  if (now - last_measure >= 10000UL) {
    float dt_h = (now - last_measure) / 3600000.0f;
    last_measure = now;

    emon.calcVI(20, 2000);  // 20 cycles, 2 s timeout
    v_rms  = emon.Vrms;
    i_rms  = emon.Irms;
    real_p = emon.realPower;
    pf     = emon.powerFactor;
    kwh_today += real_p * dt_h / 1000.0;

    update_oled();

    // MQTT publish
    char buf[256], ts_buf[32];
    time_t t = time(nullptr);
    strftime(ts_buf, sizeof(ts_buf), "%Y-%m-%dT%H:%M:%SZ", gmtime(&t));
    snprintf(buf, sizeof(buf),
      "{\"ts\":\"%s\",\"v\":%.1f,\"i\":%.3f,\"p\":%.1f,\"pf\":%.2f,\"kwh\":%.4f}",
      ts_buf, v_rms, i_rms, real_p, pf, kwh_today);
    mqtt.publish("energy/monitor", buf, true);

    // SD log every minute
    static unsigned long last_sd = 0;
    if (now - last_sd >= 60000UL) { last_sd = now; log_sd(ts_buf); }

    Serial.printf("V=%.1f I=%.3f P=%.1f PF=%.2f kWh=%.4f\n",
      v_rms, i_rms, real_p, pf, kwh_today);
  }
}
